import Foundation
import Observation

// MARK: - Protocol

/// Single source of truth for user-adjustable runtime behaviour.
/// Injectable so tests can swap in `InMemoryAppPreferences`.
@MainActor
public protocol AppPreferences: AnyObject, Observable, Sendable {
    var refreshInterval: RefreshInterval { get set }
    var launchAtLogin: Bool { get set }
    var logLevel: LogLevel { get set }
    var menuBarSegments: [MenuBarSegmentConfig] { get set }
    /// Tracks whether seeding has already run — distinguishes "fresh install"
    /// from "user deleted all segments." False on a brand-new UserDefaults suite.
    var menuBarSegmentsInitialized: Bool { get set }
    /// String inserted between adjacent segments in the menu bar label. Defaults to " | ".
    var menuBarSeparator: String { get set }
}

// MARK: - UserDefaults-backed implementation

@Observable
@MainActor
public final class UserDefaultsAppPreferences: AppPreferences {
    private let defaults: UserDefaults

    public init(defaults: UserDefaults = .standard) {
        self.defaults = defaults
    }

    public var refreshInterval: RefreshInterval {
        get {
            access(keyPath: \.refreshInterval)
            let raw = defaults.integer(forKey: AppPreferenceKeys.refreshIntervalSeconds.rawValue)
            if raw == 0 { return .default }
            return RefreshInterval(clamping: raw)
        }
        set {
            withMutation(keyPath: \.refreshInterval) {
                defaults.set(newValue.seconds, forKey: AppPreferenceKeys.refreshIntervalSeconds.rawValue)
            }
        }
    }

    public var launchAtLogin: Bool {
        get {
            access(keyPath: \.launchAtLogin)
            return defaults.bool(forKey: AppPreferenceKeys.launchAtLogin.rawValue)
        }
        set {
            withMutation(keyPath: \.launchAtLogin) {
                defaults.set(newValue, forKey: AppPreferenceKeys.launchAtLogin.rawValue)
            }
        }
    }

    public var logLevel: LogLevel {
        get {
            access(keyPath: \.logLevel)
            let raw = defaults.string(forKey: AppPreferenceKeys.logLevel.rawValue) ?? ""
            if raw.isEmpty { return .info }
            return LogLevel.from(string: raw)
        }
        set {
            withMutation(keyPath: \.logLevel) {
                defaults.set(newValue.label.lowercased(), forKey: AppPreferenceKeys.logLevel.rawValue)
            }
        }
    }

    public var menuBarSegments: [MenuBarSegmentConfig] {
        get {
            // @Observable wraps stored properties; computed ones need manual tracking so
            // SwiftUI / withObservationTracking observers are notified on mutation.
            access(keyPath: \.menuBarSegments)
            guard let data = defaults.data(forKey: AppPreferenceKeys.menuBarSegments.rawValue) else {
                return []
            }
            do {
                return try JSONDecoder().decode([MenuBarSegmentConfig].self, from: data)
            } catch {
                Loggers.app.log(.error, "Failed to decode menuBarSegments from UserDefaults: \(error)")
                return []
            }
        }
        set {
            withMutation(keyPath: \.menuBarSegments) {
                do {
                    let data = try JSONEncoder().encode(newValue)
                    defaults.set(data, forKey: AppPreferenceKeys.menuBarSegments.rawValue)
                } catch {
                    Loggers.app.log(.error, "Failed to encode menuBarSegments to UserDefaults: \(error)")
                }
            }
        }
    }

    public var menuBarSegmentsInitialized: Bool {
        get { defaults.bool(forKey: AppPreferenceKeys.menuBarSegmentsInitialized.rawValue) }
        set { defaults.set(newValue, forKey: AppPreferenceKeys.menuBarSegmentsInitialized.rawValue) }
    }

    public var menuBarSeparator: String {
        get {
            access(keyPath: \.menuBarSeparator)
            let stored = defaults.string(forKey: AppPreferenceKeys.menuBarSeparator.rawValue)
            return stored ?? " | "
        }
        set {
            withMutation(keyPath: \.menuBarSeparator) {
                defaults.set(newValue, forKey: AppPreferenceKeys.menuBarSeparator.rawValue)
            }
        }
    }
}

// MARK: - In-memory test double

/// Shared between production defaults-absent paths and test code.
@Observable
@MainActor
public final class InMemoryAppPreferences: AppPreferences {
    public var refreshInterval: RefreshInterval
    public var launchAtLogin: Bool
    public var logLevel: LogLevel
    public var menuBarSegments: [MenuBarSegmentConfig]
    public var menuBarSegmentsInitialized: Bool
    public var menuBarSeparator: String

    public init(
        refreshInterval: RefreshInterval = .default,
        launchAtLogin: Bool = false,
        logLevel: LogLevel = .info,
        menuBarSegments: [MenuBarSegmentConfig] = [],
        menuBarSegmentsInitialized: Bool = false,
        menuBarSeparator: String = " | "
    ) {
        self.refreshInterval = refreshInterval
        self.launchAtLogin = launchAtLogin
        self.logLevel = logLevel
        self.menuBarSegments = menuBarSegments
        self.menuBarSegmentsInitialized = menuBarSegmentsInitialized
        self.menuBarSeparator = menuBarSeparator
    }
}

import AppKit
import SwiftUI
import AIUsagesTrackersLib
import AppIconKit

@MainActor
final class AppDelegate: NSObject, NSApplicationDelegate {
    private var poller: UsagePoller?
    private var snapshotScheduler: SnapshotScheduler?
    private var accountMonitor: ClaudeActiveAccountMonitor?
    private var codexMonitor: CodexActiveAccountMonitor?
    private var pidGuard: AppPidGuard?
    private var usageStore: UsageStore?
    private var refreshState: RefreshState?
    private var statusItem: NSStatusItem?
    private var popover: NSPopover?
    private var appearanceObserver: NSKeyValueObservation?
    private var settingsWindowObserver: NSObjectProtocol?

    /// Shared preferences store — exposed as static so the SwiftUI Settings scene
    /// (constructed before applicationDidFinishLaunching) can access it.
    static let sharedPreferences: UserDefaultsAppPreferences = UserDefaultsAppPreferences()

    /// Shared usage store — populated in applicationDidFinishLaunching. The Settings
    /// scene is instantiated before the store exists, so it must read through this
    /// mutable holder. Nil until the first launch callback has run.
    static var sharedStore: UsageStore?

    func applicationDidFinishLaunching(_ notification: Notification) {
        NSApplication.shared.setActivationPolicy(.accessory)

        // No .app bundle ships with this SwiftPM executable, so AppKit has no
        // static icon slot — set the Dock / Cmd+Tab icon programmatically.
        if let icon = AppIconRenderer.makeImage(pixelSize: 1024) {
            NSApplication.shared.applicationIconImage = icon
        }

        let home = FileManager.default.homeDirectoryForCurrentUser.path
        let guard_ = AppPidGuard(cacheDir: "\(home)/.cache/ai-usages-tracker")
        do {
            try guard_.acquire()
        } catch AppPidGuardError.alreadyRunning(let pid, _) {
            let alert = NSAlert()
            alert.messageText = "AI Usages Tracker is already running"
            alert.informativeText = "Another instance is active (PID \(pid)). Use the menu bar icon to quit it before launching a new one."
            alert.runModal()
            NSApplication.shared.terminate(nil)
            return
        } catch {
            let alert = NSAlert()
            alert.messageText = "Failed to start AI Usages Tracker"
            alert.informativeText = error.localizedDescription
            alert.runModal()
            NSApplication.shared.terminate(nil)
            return
        }
        pidGuard = guard_

        Loggers.setPreferences(Self.sharedPreferences)

        MenuBarSegmentsSeeder.seedIfNeeded(preferences: Self.sharedPreferences)

        // Reconcile launch-at-login preference with system state — the user may
        // have disabled the entry in System Settings > Login Items directly.
        let launchService = LaunchAtLoginService.shared
        if Self.sharedPreferences.launchAtLogin != launchService.isEnabled {
            Self.sharedPreferences.launchAtLogin = launchService.isEnabled
        }

        let fileManager = UsagesFileManager.shared
        let refreshState = RefreshState()
        let codexConnector = CodexConnector()
        let poller = UsagePoller(
            connectors: [ClaudeCodeConnector(), codexConnector],
            statusConnectors: [ClaudeStatusConnector(), CodexStatusConnector()],
            fileManager: fileManager,
            refreshState: refreshState,
            preferences: Self.sharedPreferences
        )
        let accountMonitor = ClaudeActiveAccountMonitor(
            fileManager: fileManager,
            onActiveAccountChanged: { [weak poller] _ in
                await poller?.pollOnce(force: true)
            }
        )
        let codexMonitor = CodexActiveAccountMonitor(
            onActiveAccountChanged: { [weak codexConnector, weak poller] _ in
                await codexConnector?.invalidateEmailCache()
                await poller?.pollOnce(force: true)
            }
        )
        let snapshotRecorder = SnapshotRecorder()
        let historyReader = UsageHistoryReader(rootPath: snapshotRecorder.rootPath)
        let snapshotScheduler = SnapshotScheduler(
            fileManager: fileManager,
            recorder: snapshotRecorder
        )
        self.poller = poller
        self.snapshotScheduler = snapshotScheduler
        self.accountMonitor = accountMonitor

import Foundation

// MARK: - Resolution

public enum MenuBarSegmentIssue: Equatable, Sendable {
    /// `.currentlyActive` was selected but no account for the vendor is flagged active.
    case noActiveAccount(vendor: Vendor)
    /// A specific account was selected but it's absent from the usages file.
    case accountNotFound(vendor: Vendor, email: AccountEmail)
    /// The target metric name is not present on the resolved account.
    case metricNotFound(metricName: String)
    /// The metric exists but its kind doesn't match the configured display variant
    /// (e.g. timeWindow display on a pay-as-you-go metric). Happens when the user
    /// changes the underlying metric kind externally.
    case metricKindMismatch
}

public struct ResolvedMenuBarSegment: Sendable {
    public let config: MenuBarSegmentConfig
    public let rendered: MenuBarSegment?
    public let issue: MenuBarSegmentIssue?

    public init(config: MenuBarSegmentConfig, rendered: MenuBarSegment?, issue: MenuBarSegmentIssue?) {
        self.config = config
        self.rendered = rendered
        self.issue = issue
    }
}

// MARK: - Resolver

/// Converts a `MenuBarSegmentConfig` + a snapshot of usage entries into either a
/// renderable `MenuBarSegment` or a structured issue that the Settings UI can
/// surface to the user.
public enum MenuBarSegmentResolver {

    public static func resolve(
        config: MenuBarSegmentConfig,
        entries: [VendorUsageEntry],
        now: Date
    ) -> ResolvedMenuBarSegment {
        let vendorEntries = entries.filter { $0.vendor == config.vendor }

        let entry: VendorUsageEntry?
        let resolveIssue: MenuBarSegmentIssue?
        switch config.account {
        case .currentlyActive:
            if let active = vendorEntries.first(where: { $0.isActive }) {
                entry = active
                resolveIssue = nil
            } else if vendorEntries.count == 1 {
                // No account is flagged active, but there is only one — treat it as implicitly active
                // so the user sees their data without having to wait for the monitor to sync.
                entry = vendorEntries[0]
                resolveIssue = nil
            } else {
                entry = nil
                resolveIssue = .noActiveAccount(vendor: config.vendor)
            }
        case .specific(let email):
            if let match = vendorEntries.first(where: { $0.account == email }) {
                entry = match
                resolveIssue = nil
            } else {
                entry = nil
                resolveIssue = .accountNotFound(vendor: config.vendor, email: email)
            }
        }

        guard let entry else {
            return ResolvedMenuBarSegment(config: config, rendered: nil, issue: resolveIssue)
        }

        guard let metric = entry.metrics.first(where: { metricName($0) == config.metricName }) else {
            return ResolvedMenuBarSegment(
                config: config,
                rendered: nil,
                issue: .metricNotFound(metricName: config.metricName)
            )
        }

        switch (metric, config.display) {
        case let (.timeWindow(_, resetAt, windowDuration, usagePercent), .timeWindow(display)):
            let segment = renderTimeWindow(
                display: display,
                vendor: config.vendor,
                resetAt: resetAt,
                windowDuration: windowDuration,
                usagePercent: usagePercent,
                now: now
            )
            return ResolvedMenuBarSegment(config: config, rendered: segment, issue: nil)

        case let (.payAsYouGo(_, currentAmount, currency), .payAsYouGo):
            let segment = renderPayAsYouGo(currentAmount: currentAmount, currency: currency)
            return ResolvedMenuBarSegment(config: config, rendered: segment, issue: nil)

        default:
            return ResolvedMenuBarSegment(config: config, rendered: nil, issue: .metricKindMismatch)
        }
    }

    private static func metricName(_ metric: UsageMetric) -> String? {
        switch metric {
        case .timeWindow(let name, _, _, _):   return name
        case .payAsYouGo(let name, _, _):      return name
        case .unknown:                         return nil
        }
    }

    // MARK: Rendering

    private static func renderTimeWindow(
        display: TimeWindowDisplay,
        vendor: Vendor,
        resetAt: ISODate?,
        windowDuration: DurationMinutes,
        usagePercent: UsagePercent,
        now: Date
    ) -> MenuBarSegment? {
        var parts: [String] = []
        if display.showLetter, !display.letter.isEmpty {
            parts.append(display.letter)
        }
        if display.showPercent {
            parts.append("\(usagePercent.rawValue)%")
        }
        if display.showReset {
            let remaining = resetAt.map { formatRemainingTime(resetAt: $0, now: now) } ?? "???"
            parts.append(remaining)
        }
        let text = parts.joined(separator: " ")

        let tier: ConsumptionTier?
        if display.showDot {
            let theoretical = resetAt.map { theoreticalFraction(resetAt: $0, windowDuration: windowDuration, now: now) } ?? 0.0
            tier = consumptionRatio(actualPercent: usagePercent, theoreticalFraction: theoretical)
                .map { consumptionTier(ratio: $0) }
        } else {
            tier = nil
        }

        // If the user turned every visible element off, there's nothing to render
        if text.isEmpty, !display.showDot, !display.showVendorIcon {
            return nil
        }

        let vendorIcon: Vendor? = display.showVendorIcon ? vendor : nil
        return MenuBarSegment(text: text, tier: tier, showDot: display.showDot, vendorIcon: vendorIcon)
    }

    private static func renderPayAsYouGo(currentAmount: Double, currency: String) -> MenuBarSegment {
        let amount = String(format: "%.2f", currentAmount)
        return MenuBarSegment(text: "\(amount) \(currency)", tier: nil, showDot: false)
    }
}

